const css = `
@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,600;0,700;1,400;1,700&family=Outfit:wght@300;400;500;600;700&display=swap');

:root{
  --bg:#f4f1eb; --bg2:#ede8de; --surface:#fff; --card:#faf8f4;
  --sage:#3d6b4f; --sage-d:#2a4e39; --sage-l:#5a9470;
  --sage-xs:rgba(61,107,79,.09);
  --gold:#b8922a; --gold-l:#d4ac48; --gold-xs:rgba(184,146,42,.12);
  --border:rgba(61,107,79,.13); --border2:rgba(184,146,42,.18);
  --text:#1c2b22; --text2:#3a4a3f; --muted:#7a907f; --dim:#aab8ac;
  --ivory:#fdf9f2;
  --shadow:0 4px 24px rgba(30,50,35,.08);
  --shadow-lg:0 16px 60px rgba(30,50,35,.14);
  --radius:20px;
}
*,:after,:before{box-sizing:border-box;margin:0;padding:0;}
::-webkit-scrollbar{width:5px;}
::-webkit-scrollbar-thumb{background:var(--sage);border-radius:10px;}
body{margin:0;padding:0;}

.pg{min-height:100vh;background:var(--bg);font-family:'Outfit',sans-serif;color:var(--text);}

/* HERO */
.pg-hero{
  background:linear-gradient(160deg,#1e3a28,#2a5a3c,#1a4030);
  padding:80px 24px 96px;text-align:center;position:relative;overflow:hidden;
}
.hero-orb{position:absolute;border-radius:50%;filter:blur(80px);opacity:.18;pointer-events:none;animation:orbDrift 14s ease-in-out infinite;}
.hero-orb-1{width:380px;height:380px;background:var(--sage-l);top:-80px;left:-80px;}
.hero-orb-2{width:280px;height:280px;background:var(--gold-l);bottom:-40px;right:-40px;animation-delay:-6s;}
.hero-wave{position:absolute;bottom:0;left:0;right:0;height:64px;background:var(--bg);clip-path:ellipse(58% 100% at 50% 100%);}
.hero-inner{position:relative;z-index:2;max-width:800px;margin:0 auto;}
.hero-pill{
  display:inline-flex;align-items:center;gap:8px;
  background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.2);
  color:rgba(255,255,255,.85);font-size:.72rem;font-weight:600;
  letter-spacing:.2em;text-transform:uppercase;
  padding:7px 20px;border-radius:50px;margin-bottom:22px;
}
.hero-inner h1{
  font-family:'Cormorant Garamond',serif;
  font-size:clamp(36px,6vw,68px);font-weight:700;line-height:1.08;
  color:#fff;margin-bottom:16px;
}
.hero-inner h1 em{font-style:italic;color:#a8d4b8;}
.hero-inner p{color:rgba(255,255,255,.52);font-size:1rem;font-weight:300;max-width:480px;margin:0 auto 38px;line-height:1.75;}
.hero-stats{display:flex;justify-content:center;gap:48px;flex-wrap:wrap;}
.h-stat-num{font-family:'Cormorant Garamond',serif;font-size:2rem;font-weight:700;color:#a8d4b8;display:block;}
.h-stat-lbl{font-size:.68rem;color:rgba(255,255,255,.4);letter-spacing:.18em;text-transform:uppercase;}

/* SEARCH BAR */
.pg-bar{max-width:1100px;margin:-26px auto 0;padding:0 20px;position:relative;z-index:10;}
.pg-bar-inner{
  background:var(--surface);border-radius:var(--radius);padding:18px 22px;
  box-shadow:0 12px 48px rgba(30,50,35,.13);border:1px solid var(--border);
  display:flex;gap:12px;align-items:center;flex-wrap:wrap;
}
.pg-search{
  flex:1;min-width:180px;display:flex;align-items:center;gap:10px;
  background:var(--bg);border:1.5px solid var(--border);border-radius:50px;padding:10px 18px;transition:all .2s;
}
.pg-search:focus-within{border-color:var(--sage);box-shadow:0 0 0 3px rgba(61,107,79,.1);}
.pg-search-icon{font-size:15px;opacity:.5;flex-shrink:0;}
.pg-search input{border:none;background:transparent;outline:none;font-family:'Outfit',sans-serif;font-size:.875rem;color:var(--text);width:100%;}
.pg-search input::placeholder{color:var(--dim);}
.pg-sort{
  background:var(--bg);border:1.5px solid var(--border);border-radius:50px;
  padding:10px 14px;font-family:'Outfit',sans-serif;font-size:.85rem;
  font-weight:500;color:var(--text);cursor:pointer;outline:none;
}
.pg-sort:focus{border-color:var(--sage);}
.pg-view-btns{display:flex;gap:6px;}
.btn-icon{
  width:38px;height:38px;border-radius:50%;border:1.5px solid var(--border);
  background:transparent;cursor:pointer;font-size:15px;
  display:flex;align-items:center;justify-content:center;
  transition:all .2s;color:var(--muted);
}
.btn-icon:hover,.btn-icon.active{background:var(--sage-xs);border-color:var(--sage);color:var(--sage);}

/* CATEGORY CHIPS */
.pg-cats{max-width:1100px;margin:18px auto 0;padding:0 20px;display:flex;gap:8px;flex-wrap:wrap;}
.pg-cat{
  padding:8px 18px;border-radius:50px;border:1.5px solid var(--border);
  background:var(--surface);color:var(--muted);font-family:'Outfit',sans-serif;
  font-size:.8rem;font-weight:500;cursor:pointer;transition:all .2s;
  display:flex;align-items:center;gap:6px;
}
.pg-cat:hover{border-color:var(--sage);color:var(--sage);}
.pg-cat.active{background:var(--sage);border-color:var(--sage);color:#fff;box-shadow:0 4px 16px rgba(61,107,79,.3);}
.pg-cat-cnt{font-size:.68rem;padding:1px 7px;border-radius:50px;background:rgba(0,0,0,.08);}
.pg-cat.active .pg-cat-cnt{background:rgba(255,255,255,.25);}

/* INFO */
.pg-info{max-width:1100px;margin:18px auto 0;padding:0 20px;display:flex;justify-content:space-between;align-items:center;}
.pg-results{font-size:.82rem;color:var(--muted);}
.pg-results strong{color:var(--text);font-weight:600;}
.pg-clear{font-size:.78rem;color:var(--sage);cursor:pointer;font-weight:600;background:none;border:none;font-family:'Outfit',sans-serif;}

/* GRID */
.pg-grid{
  max-width:1100px;margin:20px auto 0;padding:0 20px 100px;
  display:grid;gap:22px;grid-template-columns:repeat(auto-fill,minmax(250px,1fr));
}
.pg-grid.list-view{grid-template-columns:1fr;}

/* CARD */
.pg-card{
  background:var(--surface);border-radius:var(--radius);
  border:1px solid var(--border);overflow:hidden;
  cursor:pointer;position:relative;box-shadow:var(--shadow);
  transition:transform .4s cubic-bezier(.34,1.56,.64,1),box-shadow .4s ease,border-color .3s ease;
  animation:fadeUp .45s ease both;
}
.pg-card:hover{transform:translateY(-10px);box-shadow:0 20px 60px rgba(30,50,35,.16);border-color:rgba(61,107,79,.3);}
.pg-card.list-view{display:grid;grid-template-columns:230px 1fr;}
.pg-card.list-view:hover{transform:translateY(-5px);}

.pg-img-wrap{position:relative;overflow:hidden;aspect-ratio:4/3;background:var(--bg2);}
.pg-card.list-view .pg-img-wrap{aspect-ratio:unset;min-height:190px;}
.pg-img{width:100%;height:100%;object-fit:cover;transition:transform .55s ease;}
.pg-card:hover .pg-img{transform:scale(1.07);}

/* Badges */
.pg-badge{position:absolute;top:12px;left:12px;padding:4px 11px;border-radius:50px;font-size:.65rem;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:#fff;}
.badge-popular{background:var(--sage);}
.badge-new{background:#3ecf8e;}
.badge-premium{background:#7c5cfc;}
.badge-verified{background:var(--gold);}

/* Wishlist */
.pg-wish{
  position:absolute;top:12px;right:12px;width:34px;height:34px;border-radius:50%;
  background:rgba(255,255,255,.92);border:none;cursor:pointer;
  display:flex;align-items:center;justify-content:center;font-size:16px;
  transition:all .25s;opacity:0;transform:scale(.7);
}
.pg-card:hover .pg-wish{opacity:1;transform:scale(1);}
.pg-wish.liked{opacity:1;transform:scale(1);}
.pg-wish:hover{transform:scale(1.18)!important;}

/* Quick view */
.pg-quick{
  position:absolute;bottom:12px;left:50%;transform:translateX(-50%) translateY(10px);
  background:rgba(255,255,255,.96);border:none;border-radius:50px;
  padding:7px 18px;font-family:'Outfit',sans-serif;font-size:.75rem;font-weight:600;
  color:var(--sage-d);cursor:pointer;white-space:nowrap;opacity:0;transition:all .25s;
}
.pg-card:hover .pg-quick{opacity:1;transform:translateX(-50%) translateY(0);}

/* Body */
.pg-body{padding:18px;}
.pg-card.list-view .pg-body{padding:22px 26px;display:flex;flex-direction:column;justify-content:center;}
.pg-cat-tag{font-size:.68rem;font-weight:700;letter-spacing:.18em;text-transform:uppercase;color:var(--sage);margin-bottom:6px;display:flex;align-items:center;gap:5px;}
.pg-cat-tag::before{content:'';display:inline-block;width:5px;height:5px;border-radius:50%;background:var(--sage-l);}
.pg-pname{font-family:'Cormorant Garamond',serif;font-size:1.25rem;font-weight:700;color:var(--text);margin:0 0 3px;line-height:1.25;}
.pg-card.list-view .pg-pname{font-size:1.55rem;}
.pg-age{font-size:.75rem;color:var(--muted);margin-bottom:6px;}
.pg-desc{font-size:.8rem;color:var(--muted);line-height:1.65;margin-bottom:10px;display:none;}
.pg-card.list-view .pg-desc{display:block;}
.pg-rating{display:flex;align-items:center;gap:5px;margin-bottom:13px;}
.pg-stars{color:var(--gold);font-size:.75rem;letter-spacing:1px;}
.pg-rev{font-size:.7rem;color:var(--dim);}
.pg-price-row{display:flex;align-items:center;justify-content:space-between;gap:8px;}
.pg-price{font-family:'Cormorant Garamond',serif;font-size:1.55rem;font-weight:700;color:var(--sage-d);line-height:1;}
.pg-price sup{font-size:.85rem;font-family:'Outfit',sans-serif;font-weight:500;color:var(--muted);}
.pg-btns{display:flex;gap:7px;align-items:center;}
.pg-cart-btn{
  padding:8px 14px;border-radius:50px;border:none;background:var(--sage-l);color:#fff;
  font-family:'Outfit',sans-serif;font-size:.75rem;font-weight:600;cursor:pointer;
  transition:all .22s;white-space:nowrap;display:flex;align-items:center;gap:5px;
  box-shadow:0 4px 12px rgba(61,107,79,.25);
}
.pg-cart-btn:hover{background:var(--sage-d);}
.pg-cart-btn.added{background:#1D9E75;}
.pg-wa-btn{
  width:34px;height:34px;border-radius:50%;border:1.5px solid var(--border2);
  background:var(--gold-xs);cursor:pointer;font-size:14px;transition:all .2s;
  display:flex;align-items:center;justify-content:center;flex-shrink:0;
}
.pg-wa-btn:hover{border-color:var(--gold);transform:scale(1.1);}

/* MODAL */
.pg-modal-bg{
  position:fixed;inset:0;background:rgba(10,22,14,.75);z-index:9999;
  display:flex;align-items:center;justify-content:center;padding:20px;
  backdrop-filter:blur(8px);
}
.pg-modal{
  background:var(--ivory);border-radius:var(--radius);max-width:680px;width:100%;
  max-height:90vh;overflow-y:auto;position:relative;
  box-shadow:var(--shadow-lg);border:1px solid var(--border);
}
.pg-modal-img{width:100%;height:280px;object-fit:cover;border-radius:var(--radius) var(--radius) 0 0;}
.pg-modal-close{
  position:absolute;top:14px;right:14px;width:36px;height:36px;border-radius:50%;
  background:rgba(255,255,255,.95);border:none;font-size:16px;cursor:pointer;
  display:flex;align-items:center;justify-content:center;transition:all .22s;
}
.pg-modal-close:hover{transform:rotate(90deg);}
.pg-modal-body{padding:24px 28px 30px;}
.pg-modal-name{font-family:'Cormorant Garamond',serif;font-size:1.9rem;font-weight:700;color:var(--text);margin:0 0 8px;}
.pg-modal-price{font-family:'Cormorant Garamond',serif;font-size:2rem;font-weight:700;color:var(--sage-d);margin:0 0 16px;}
.pg-modal-feats{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:20px;}
.pg-feat{background:var(--bg);border:1px solid var(--border);border-radius:14px;padding:11px 13px;font-size:.8rem;color:var(--muted);}
.pg-feat strong{display:block;font-size:.85rem;font-weight:600;color:var(--text2);margin-bottom:2px;}
.pg-modal-actions{display:flex;gap:10px;flex-wrap:wrap;margin-bottom:10px;}
.pg-modal-cart-btn{
  flex:1;min-width:130px;padding:12px 18px;background:var(--sage-l);color:#fff;border:none;border-radius:50px;
  font-family:'Outfit',sans-serif;font-size:.875rem;font-weight:600;cursor:pointer;
  display:flex;align-items:center;justify-content:center;gap:8px;
  box-shadow:0 6px 20px rgba(61,107,79,.3);transition:all .22s;
}
.pg-modal-cart-btn:hover{background:var(--sage-d);}
.pg-modal-wa-btn{
  padding:12px 20px;border-radius:50px;border:1.5px solid var(--border2);background:var(--gold-xs);
  font-family:'Outfit',sans-serif;font-size:.875rem;font-weight:600;color:var(--gold);
  cursor:pointer;display:flex;align-items:center;gap:7px;transition:all .22s;
}
.pg-modal-wa-btn:hover{background:var(--gold);color:#fff;}
.pg-modal-wish-btn{padding:12px 14px;border-radius:50px;border:1.5px solid var(--border);background:transparent;font-size:18px;cursor:pointer;}
.pg-buynow{
  width:100%;padding:13px;background:linear-gradient(135deg,var(--gold),var(--gold-l));
  color:#fff;border:none;border-radius:50px;font-family:'Outfit',sans-serif;
  font-size:.9rem;font-weight:700;cursor:pointer;transition:all .22s;
  display:flex;align-items:center;justify-content:center;gap:8px;
  box-shadow:0 6px 20px rgba(184,146,42,.3);
}
.pg-buynow:hover{opacity:.88;}

/* SKELETON */
.pg-skel{background:var(--surface);border-radius:var(--radius);overflow:hidden;border:1px solid var(--border);}
.pg-skel-img{height:190px;background:linear-gradient(90deg,var(--bg2) 25%,var(--bg) 50%,var(--bg2) 75%);background-size:200%;animation:shimmer 1.5s ease infinite;}
.pg-skel-body{padding:18px;}
.pg-skel-line{height:11px;border-radius:6px;margin-bottom:10px;background:linear-gradient(90deg,var(--bg2) 25%,var(--bg) 50%,var(--bg2) 75%);background-size:200%;animation:shimmer 1.5s ease infinite;}
.pg-skel-line.w70{width:70%;}.pg-skel-line.w50{width:50%;}

/* EMPTY */
.pg-empty{grid-column:1/-1;text-align:center;padding:80px 20px;}
.pg-empty-icon{font-size:60px;display:block;margin-bottom:16px;}
.pg-empty h3{font-family:'Cormorant Garamond',serif;font-size:1.5rem;font-weight:700;color:var(--text);margin:0 0 8px;}
.pg-empty p{font-size:.875rem;color:var(--muted);}

/* TOAST */
.pg-toast{
  position:fixed;bottom:26px;right:26px;z-index:99999;
  background:var(--sage-d);color:#fff;border-radius:50px;
  padding:13px 22px;font-size:.875rem;font-weight:500;
  box-shadow:0 8px 32px rgba(0,0,0,.2);display:flex;align-items:center;gap:10px;
  transform:translateY(80px);opacity:0;transition:all .35s cubic-bezier(.34,1.46,.64,1);
